import{_ as i,o as a,c as t,ag as l}from"./chunks/framework.ePeAWSvT.js";const h=JSON.parse('{"title":"COURS : L’ULCÈRE GASTRIQUE","description":"","frontmatter":{},"headers":[],"relativePath":"matieres/sante/cours/ulcère-gastrique-neuro.md","filePath":"matieres/sante/cours/ulcère-gastrique-neuro.md"}'),r={name:"matieres/sante/cours/ulcère-gastrique-neuro.md"};function s(o,e,n,u,c,d){return a(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="cours-l-ulcere-gastrique" tabindex="-1">COURS : L’ULCÈRE GASTRIQUE <a class="header-anchor" href="#cours-l-ulcere-gastrique" aria-label="Permalink to &quot;COURS : L’ULCÈRE GASTRIQUE&quot;">​</a></h1><h2 id="_1️⃣-definition" tabindex="-1">1️⃣ Définition <a class="header-anchor" href="#_1️⃣-definition" aria-label="Permalink to &quot;1️⃣ Définition&quot;">​</a></h2><p>L’ulcère gastrique est une <strong>lésion de la muqueuse de l’estomac</strong>.</p><p>Il résulte d’un déséquilibre entre :</p><ul><li>les facteurs agressifs (acide gastrique)</li><li>les mécanismes de protection de la muqueuse.</li></ul><hr><h2 id="_2️⃣-causes" tabindex="-1">2️⃣ Causes <a class="header-anchor" href="#_2️⃣-causes" aria-label="Permalink to &quot;2️⃣ Causes&quot;">​</a></h2><p>Les principales causes sont :</p><ul><li>infection par Helicobacter pylori</li><li>prise d’anti-inflammatoires (AINS)</li><li>stress</li><li>tabagisme</li><li>alcool</li></ul><hr><h2 id="_3️⃣-symptomes" tabindex="-1">3️⃣ Symptômes <a class="header-anchor" href="#_3️⃣-symptomes" aria-label="Permalink to &quot;3️⃣ Symptômes&quot;">​</a></h2><ul><li>douleur brûlante à l’estomac</li><li>douleur après les repas</li><li>nausées</li><li>vomissements</li><li>perte d’appétit</li></ul><hr><h2 id="_4️⃣-complications" tabindex="-1">4️⃣ Complications <a class="header-anchor" href="#_4️⃣-complications" aria-label="Permalink to &quot;4️⃣ Complications&quot;">​</a></h2><ul><li>hémorragie digestive</li><li>perforation de l’estomac</li><li>obstruction digestive</li></ul><hr><h2 id="_5️⃣-diagnostic" tabindex="-1">5️⃣ Diagnostic <a class="header-anchor" href="#_5️⃣-diagnostic" aria-label="Permalink to &quot;5️⃣ Diagnostic&quot;">​</a></h2><ul><li>endoscopie digestive</li><li>test Helicobacter pylori</li><li>analyses sanguines</li></ul><hr><h2 id="_6️⃣-traitement" tabindex="-1">6️⃣ Traitement <a class="header-anchor" href="#_6️⃣-traitement" aria-label="Permalink to &quot;6️⃣ Traitement&quot;">​</a></h2><ul><li>inhibiteurs de la pompe à protons</li><li>antibiotiques (si Helicobacter pylori)</li><li>arrêt des AINS</li><li>régime alimentaire adapté</li></ul>',21)])])}const p=i(r,[["render",s]]);export{h as __pageData,p as default};
